import { useEffect, useState } from 'react';
import Layout from '../components/Layout';
import { bolgeAPI } from '../api';

const DURUM_LABEL = { yolda: 'Yolda', ulastu: 'Ulaştı', tamamlandi: 'Tamamlandı' };
const DURUM_BADGE = { yolda: 'badge-warning', ulastu: 'badge-success', tamamlandi: 'badge-neutral' };

export default function BolgeTirlar() {
  const [tirlar, setTirlar] = useState([]);
  const [loading, setLoading] = useState(true);
  const [durumFiltre, setDurumFiltre] = useState('');

  useEffect(() => {
    bolgeAPI.getTirlar()
      .then(r => setTirlar(r.data))
      .catch(() => {})
      .finally(() => setLoading(false));
  }, []);

  const filtered = durumFiltre ? tirlar.filter(t => t.durum === durumFiltre) : tirlar;

  return (
    <Layout title="Bölge TIR Hareketleri">
      <div className="card">
        <div className="card-header">
          <div className="card-title">TIR Hareketleri ({filtered.length})</div>
          <select
            className="form-control"
            style={{ width: 160 }}
            value={durumFiltre}
            onChange={e => setDurumFiltre(e.target.value)}
          >
            <option value="">Tüm Durumlar</option>
            <option value="yolda">Yolda</option>
            <option value="ulastu">Ulaştı</option>
            <option value="tamamlandi">Tamamlandı</option>
          </select>
        </div>

        {loading ? (
          <div className="loading"><div className="spinner" /> Yükleniyor...</div>
        ) : filtered.length === 0 ? (
          <div className="empty-state">
            <div className="empty-icon">🚛</div>
            <div className="empty-text">TIR bulunamadı</div>
          </div>
        ) : (
          <div className="table-wrapper">
            <table>
              <thead>
                <tr>
                  <th>#</th>
                  <th>Plaka</th>
                  <th>Şoför</th>
                  <th>Kaynak</th>
                  <th>Hedef</th>
                  <th>Durum</th>
                  <th>Gönderim</th>
                  <th>Ulaşma</th>
                </tr>
              </thead>
              <tbody>
                {filtered.map(t => (
                  <tr key={t.id}>
                    <td style={{ color: 'var(--text3)', fontFamily: 'IBM Plex Mono' }}>{t.id}</td>
                    <td style={{ fontFamily: 'IBM Plex Mono', fontWeight: 600 }}>{t.plaka}</td>
                    <td>{t.sofor_ad || '—'}</td>
                    <td>
                      {t.kaynak_merkez
                        ? <>{t.kaynak_merkez.ad}<br /><span style={{ color: 'var(--text3)', fontSize: 11 }}>{t.kaynak_merkez.il}</span></>
                        : '—'
                      }
                    </td>
                    <td>
                      {t.hedef_merkez
                        ? <>{t.hedef_merkez.ad}<br /><span style={{ color: 'var(--text3)', fontSize: 11 }}>{t.hedef_merkez.il}</span></>
                        : '—'
                      }
                    </td>
                    <td><span className={`badge ${DURUM_BADGE[t.durum]}`}>{DURUM_LABEL[t.durum]}</span></td>
                    <td style={{ fontSize: 12, color: 'var(--text2)' }}>{new Date(t.created_at).toLocaleString('tr-TR')}</td>
                    <td style={{ fontSize: 12, color: 'var(--text2)' }}>
                      {t.ulasma_zamani ? new Date(t.ulasma_zamani).toLocaleString('tr-TR') : '—'}
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}
      </div>
    </Layout>
  );
}
